using namespace std;

long long solve(vector<long long> prices, vector<long long> strategy, long long k) {
    int n = prices.size();
    long long original_profit = 0;
    for (int i = 0; i < n; ++i) {
        original_profit += strategy[i] * prices[i];
    }

    long long max_profit = original_profit;
    int half_k = k / 2;

    vector<long long> prefix_diff(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        long long original = strategy[i] * prices[i];
        long long modified = 0;
        if (i < half_k) {
            modified = 0 * prices[i];
        } else {
            modified = 1 * prices[i];
        }
        prefix_diff[i + 1] = prefix_diff[i] + (modified - original);
    }

    for (int i = 0; i <= n - k; ++i) {
        long long current_diff = prefix_diff[i + k] - prefix_diff[i];
        max_profit = max(max_profit, original_profit + current_diff);
    }

    return max_profit;
}

